    'Sports': ["sport", "soccer", "football", "baseball", "basketball", "tennis", "golf", "hockey", "olympics", "olympic", "tournament", "championship", "league", "team", "athlete", "coach", "game", "match", "score", "cup", "medal", "nfl", "nba", "mlb", "fifa"],
